1	/*
2	This file trains the GPT-2 model.
3	This version is the clean, minimal, reference. As such:
4	- it runs on CPU.
5	- it does not make the code too complex; it is readable.
6	- it does not use any processor-specific instructions, intrinsics and such.
7	- it _does_ use a few OpenMP pragmas because this is a large speedup at very low cost
8	There will be other versions of this code that specialize it and make it fast.
9	*/
10	
11	#include <stdio.h>
12	#include <stdlib.h>
13	#include <ctype.h>
14	#include <stdint.h>
15	#include <assert.h>
16	#include <math.h>
17	#include <time.h>
18	#include <string.h>
19	#include <unistd.h>
20	#ifdef OMP
21	#include <omp.h>
22	#endif
23	// our own utilities
24	// defines: fopenCheck, freadCheck, fcloseCheck, fseekCheck, mallocCheck
25	#include "llmc/utils.h"
26	// defines: tokenizer_init, tokenizer_decode, tokenizer_free
27	#include "llmc/tokenizer.h"
28	// defines: dataloader_init, dataloader_reset, dataloader_next_batch, dataloader_free
29	#include "llmc/dataloader.h"
