31	// ----------------------------------------------------------------------------
32	// all the individual layers' forward and backward passes
33	// B = batch_size, T = sequence_length, C = channels, V = vocab_size
34	
35	void encoder_forward(float* out,
36	                   int* inp, float* wte, float* wpe,
37	                   int B, int T, int C) {
38	    // out is (B,T,C). At each position (b,t), a C-dimensional vector summarizing token & position
39	    // inp is (B,T) of integers, holding the token ids at each (b,t) position
40	    // wte is (V,C) of token embeddings, short for "weight token embeddings"
41	    // wpe is (maxT,C) of position embeddings, short for "weight positional embedding"
42	    for (int b = 0; b < B; b++) {
43	        for (int t = 0; t < T; t++) {
44	            // seek to the output position in out[b,t,:]
45	            float* out_bt = out + b * T * C + t * C;
46	            // get the index of the token at inp[b, t]
47	            int ix = inp[b * T + t];
48	            // seek to the position in wte corresponding to the token
49	            float* wte_ix = wte + ix * C;
50	            // seek to the position in wpe corresponding to the position
51	            float* wpe_t = wpe + t * C;
52	            // add the two vectors and store the result in out[b,t,:]
53	            for (int i = 0; i < C; i++) {
54	                out_bt[i] = wte_ix[i] + wpe_t[i];
55	            }
56	        }
57	    }
58	}
59	
60	void encoder_backward(float* dwte, float* dwpe,
61	                      float* dout, int* inp,
62	                      int B, int T, int C) {
63	    for (int b = 0; b < B; b++) {
64	        for (int t = 0; t < T; t++) {
65	            float* dout_bt = dout + b * T * C + t * C;
66	            int ix = inp[b * T + t];
67	            float* dwte_ix = dwte + ix * C;
68	            float* dwpe_t = dwpe + t * C;
69	            for (int i = 0; i < C; i++) {
70	                float d = dout_bt[i];
71	                dwte_ix[i] += d;
72	                dwpe_t[i] += d;
73	            }
74	        }
75	    }
76	}
77	
78	void layernorm_forward(float* out, float* mean, float* rstd,
79	                       float* inp, float* weight, float* bias,
80	                       int B, int T, int C) {
81	    // reference: https://pytorch.org/docs/stable/generated/torch.nn.LayerNorm.html
82	    // both inp and out are (B,T,C) of the activations
83	    // mean and rstd are (B,T) buffers, to be used later in backward pass
84	    // at each position (b,t) of the input, the C-dimensional vector
85	    // of activations gets normalized, then scaled and shifted
86	    float eps = 1e-5f;
87	    for (int b = 0; b < B; b++) {
88	        for (int t = 0; t < T; t++) {
89	            // seek to the input position inp[b,t,:]
90	            float* x = inp + b * T * C + t * C;
91	            // calculate the mean
92	            float m = 0.0f;
93	            for (int i = 0; i < C; i++) {
94	                m += x[i];
95	            }
96	            m = m/C;
97	            // calculate the variance (without any bias correction)
98	            float v = 0.0f;
99	            for (int i = 0; i < C; i++) {
100	                float xshift = x[i] - m;
101	                v += xshift * xshift;
102	            }
103	            v = v/C;
104	            // calculate the rstd (reciprocal standard deviation)
105	            float s = 1.0f / sqrtf(v + eps);
106	            // seek to the output position in out[b,t,:]
107	            float* out_bt = out + b * T * C + t * C;
108	            for (int i = 0; i < C; i++) {
109	                float n = (s * (x[i] - m)); // normalize
110	                float o = n * weight[i] + bias[i]; // scale and shift
111	                out_bt[i] = o; // write
112	            }
113	            // cache the mean and rstd for the backward pass later
114	            mean[b * T + t] = m;
115	            rstd[b * T + t] = s;
116	        }
117	    }
118	}
119	
120	void layernorm_backward(float* dinp, float* dweight, float* dbias,
121	                        float* dout, float* inp, float* weight, float* mean, float* rstd,
122	                        int B, int T, int C) {
123	    for (int b = 0; b < B; b++) {
124	        for (int t = 0; t < T; t++) {
125	            float* dout_bt = dout + b * T * C + t * C;
126	            float* inp_bt = inp + b * T * C + t * C;
127	            float* dinp_bt = dinp + b * T * C + t * C;
128	            float mean_bt = mean[b * T + t];
129	            float rstd_bt = rstd[b * T + t];
130	
131	            // first: two reduce operations
132	            float dnorm_mean = 0.0f;
133	            float dnorm_norm_mean = 0.0f;
134	            for (int i = 0; i < C; i++) {
135	                float norm_bti = (inp_bt[i] - mean_bt) * rstd_bt;
136	                float dnorm_i = weight[i] * dout_bt[i];
137	                dnorm_mean += dnorm_i;
138	                dnorm_norm_mean += dnorm_i * norm_bti;
139	            }
140	            dnorm_mean = dnorm_mean / C;
141	            dnorm_norm_mean = dnorm_norm_mean / C;
142	
143	            // now iterate again and accumulate all the gradients
144	            for (int i = 0; i < C; i++) {
145	                float norm_bti = (inp_bt[i] - mean_bt) * rstd_bt;
146	                float dnorm_i = weight[i] * dout_bt[i];
147	                // gradient contribution to bias
148	                dbias[i] += dout_bt[i];
149	                // gradient contribution to weight
150	                dweight[i] += norm_bti * dout_bt[i];
151	                // gradient contribution to input
152	                float dval = 0.0f;
153	                dval += dnorm_i; // term 1
154	                dval -= dnorm_mean; // term 2
155	                dval -= norm_bti * dnorm_norm_mean; // term 3
156	                dval *= rstd_bt; // final scale
157	                dinp_bt[i] += dval;
158	            }
159	        }
160	    }
161	}
162	
163	void matmul_forward_naive(float* out,
164	                         const float* inp, const float* weight, const float* bias,
165	                         int B, int T, int C, int OC) {
166	    // the most naive implementation of matrix multiplication
167	    // this serves as an algorithmic reference, and as a fallback for
168	    // unfriendly input shapes inside matmul_forward(), below.
169	    #pragma omp parallel for collapse(2)
170	    for (int b = 0; b < B; b++) {
171	        for (int t = 0; t < T; t++) {
172	            int bt = b * T + t;
173	            for (int o = 0; o < OC; o++) {
174	                float val = (bias != NULL) ? bias[o] : 0.0f;
175	                for (int i = 0; i < C; i++) {
176	                    val += inp[bt * C + i] * weight[o*C + i];
177	                }
178	                out[bt * OC + o] = val;
179	            }
180	        }
181	    }
182	}
183	
184	void matmul_forward(float* out,
185	                    const float* inp, const float* weight, const float* bias,
186	                    int B, int T, int C, int OC) {
187	    // most of the running time is spent here and in matmul_backward
188	    // therefore, the implementation below is very mildly optimized
189	    // this function is otherwise identical to that of matmul_forward_naive()
190	    // OC is short for "output channels"
191	    // inp is (B,T,C), weight is (OC, C), bias is (OC)
192	    // out will be (B,T,OC)
193	
194	    // make sure the tiled loop will be correct or fallback to naive version
195	    const int LOOP_UNROLL = 8;
196	    if (B*T % LOOP_UNROLL != 0) {
197	        matmul_forward_naive(out, inp, weight, bias, B, T, C, OC);
198	        return;
199	    }
200	
201	    // collapse the B and T loops into one and turn it into a strided loop.
202	    // then we can tile the inner loop, and reuse the loaded weight LOOP_UNROLL many times
203	    #pragma omp parallel for
204	    for (int obt = 0; obt < B * T; obt += LOOP_UNROLL) {
205	        for (int o = 0; o < OC; o++) {
206	            // we'll keep LOOP_UNROLL many results in registers
207	            float result[LOOP_UNROLL];
208	            // initialize the bias, if it exists
209	            for (int ibt = 0; ibt < LOOP_UNROLL; ibt++) {
210	                result[ibt] = (bias != NULL) ? bias[o] : 0.0f;
211	            }
212	            // inner loops. Because we do LOOP_UNROLL steps of inner bt, we can cache
213	            // the value of weight[i + o * C] and reuse it.
214	            // we compile with -Ofast, so the compiler will turn the inner loop into FMAs
215	            for (int i = 0; i < C; i++) {
216	                float w = weight[i + o * C];
217	                for (int ibt = 0; ibt < LOOP_UNROLL; ibt++) {
218	                    int bt = obt + ibt;
219	                    result[ibt] += inp[bt * C + i] * w;
220	                }
221	            }
222	            // write back results to main memory
223	            for (int ibt = 0; ibt < LOOP_UNROLL; ibt++) {
224	                int bt = obt + ibt;
225	                out[bt * OC + o] = result[ibt];
226	            }
227	        }
228	    }
229	}
230	
231	void matmul_backward(float* dinp, float* dweight, float* dbias,
232	                     const float* dout, const float* inp, const float* weight,
233	                     int B, int T, int C, int OC) {
234	    // most of the running time is spent here and in matmul_forward
235	    // this backward could be done in a single "round" of loops
236	    // but that doesn't afford an efficient parallelization strategy
237	
238	    // backward into inp first, parallelize over B,T
239	    #pragma omp parallel for collapse(2)
240	    for (int b = 0; b < B; b++) {
241	        for (int t = 0; t < T; t++) {
242	            const float* dout_bt = dout + b * T * OC + t * OC;
243	            float* dinp_bt = dinp + b * T * C + t * C;
244	            for (int o = 0; o < OC; o++) {
245	                const float* wrow = weight + o*C;
246	                float d = dout_bt[o];
247	                for (int i = 0; i < C; i++) {
248	                    dinp_bt[i] += wrow[i] * d;
249	                }
250	            }
251	        }
252	    }
253	    // backward into weight/bias, parallelize over output channels OC
254	    #pragma omp parallel for
255	    for (int o = 0; o < OC; o++) {
256	        for (int b = 0; b < B; b++) {
257	            for (int t = 0; t < T; t++) {
258	                const float* dout_bt = dout + b * T * OC + t * OC;
259	                const float* inp_bt = inp + b * T * C + t * C;
260	                float* dwrow = dweight + o*C;
261	                float d = dout_bt[o];
262	                if (dbias != NULL) { dbias[o] += d; }
263	                for (int i = 0; i < C; i++) {
264	                    dwrow[i] += inp_bt[i] * d;
265	                }
266	            }
267	        }
268	    }
269	}
270	
271	void attention_forward(float* out, float* preatt, float* att,
272	                       float* inp,
273	                       int B, int T, int C, int NH) {
274	    // input is (B, T, 3C) holding the query, key, value (Q, K, V) vectors
275	    // preatt, att are (B, NH, T, T). NH = number of heads, T = sequence length
276	    // that holds the pre-attention and post-attention scores (used in backward)
277	    // output is (B, T, C)
278	    // attention is the only layer that mixes information across time
279	    // every other operation is applied at every (b,t) position independently
280	    // (and of course, no layer mixes information across batch)
281	    int C3 = C*3;
282	    int hs = C / NH; // head size
283	    float scale = 1.0 / sqrtf(hs);
284	
285	    #pragma omp parallel for collapse(3)
286	    for (int b = 0; b < B; b++) {
287	        for (int t = 0; t < T; t++) {
288	            for (int h = 0; h < NH; h++) {
289	                float* query_t = inp + b * T * C3 + t * C3 + h * hs;
290	                float* preatt_bth = preatt + b*NH*T*T + h*T*T + t*T;
291	                float* att_bth = att + b*NH*T*T + h*T*T + t*T;
292	
293	                // pass 1: calculate query dot key and maxval
294	                float maxval = -10000.0f; // TODO something better
295	                for (int t2 = 0; t2 <= t; t2++) {
296	                    float* key_t2 = inp + b * T * C3 + t2 * C3 + h * hs + C; // +C because it's key
297	
298	                    // (query_t) dot (key_t2)
299	                    float val = 0.0f;
300	                    for (int i = 0; i < hs; i++) {
301	                        val += query_t[i] * key_t2[i];
302	                    }
303	                    val *= scale;
304	                    if (val > maxval) {
305	                        maxval = val;
306	                    }
307	
308	                    preatt_bth[t2] = val;
309	                }
310	
311	                // pass 2: calculate the exp and keep track of sum
312	                // maxval is being calculated and subtracted only for numerical stability
313	                float expsum = 0.0f;
314	                for (int t2 = 0; t2 <= t; t2++) {
315	                    float expv = expf(preatt_bth[t2] - maxval);
316	                    expsum += expv;
317	                    att_bth[t2] = expv;
318	                }
319	                float expsum_inv = expsum == 0.0f ? 0.0f : 1.0f / expsum;
320	
321	                // pass 3: normalize to get the softmax
322	                for (int t2 = 0; t2 < T; t2++) {
323	                    if (t2 <= t) {
324	                        att_bth[t2] *= expsum_inv;
325	                    } else {
326	                        // causal attention mask. not strictly necessary to set to zero here
327	                        // only doing this explicitly for debugging and checking to PyTorch
328	                        att_bth[t2] = 0.0f;
329	                    }
330	                }
331	
332	                // pass 4: accumulate weighted values into the output of attention
333	                float* out_bth = out + b * T * C + t * C + h * hs;
334	                for (int i = 0; i < hs; i++) { out_bth[i] = 0.0f; }
335	                for (int t2 = 0; t2 <= t; t2++) {
336	                    float* value_t2 = inp + b * T * C3 + t2 * C3 + h * hs + C*2; // +C*2 because it's value
337	                    float att_btht2 = att_bth[t2];
338	                    for (int i = 0; i < hs; i++) {
339	                        out_bth[i] += att_btht2 * value_t2[i];
340	                    }
341	                }
342	            }
343	        }
344	    }
345	}
346	
347	void attention_backward(float* dinp, float* dpreatt, float* datt,
348	                        float* dout, float* inp, float* att,
349	                        int B, int T, int C, int NH) {
350	    // inp/dinp are (B, T, 3C) Q,K,V
351	    // att/datt/dpreatt are (B, NH, T, T)
352	    // dout is (B, T, C)
353	    int C3 = C*3;
354	    int hs = C / NH; // head size
355	    float scale = 1.f / sqrtf(hs);
356	
357	    for (int b = 0; b < B; b++) {
358	        for (int t = 0; t < T; t++) {
359	            for (int h = 0; h < NH; h++) {
360	                float* att_bth = att + b*NH*T*T + h*T*T + t*T;
361	                float* datt_bth = datt + b*NH*T*T + h*T*T + t*T;
362	                float* dpreatt_bth = dpreatt + b*NH*T*T + h*T*T + t*T;
363	                float* dquery_t = dinp + b * T * C3 + t * C3 + h * hs;
364	                float* query_t = inp + b * T * C3 + t * C3 + h * hs;
365	
366	                // backward pass 4, through the value accumulation
367	                float* dout_bth = dout + b * T * C + t * C + h * hs;
368	                for (int t2 = 0; t2 <= t; t2++) {
369	                    float* value_t2 = inp + b * T * C3 + t2 * C3 + h * hs + C*2; // +C*2 because it's value
370	                    float* dvalue_t2 = dinp + b * T * C3 + t2 * C3 + h * hs + C*2;
371	                    for (int i = 0; i < hs; i++) {
372	                        // in the forward pass this was:
373	                        // out_bth[i] += att_bth[t2] * value_t2[i];
374	                        // so now we have:
375	                        datt_bth[t2] += value_t2[i] * dout_bth[i];
376	                        dvalue_t2[i] += att_bth[t2] * dout_bth[i];
377	                    }
378	                }
379	
380	                // backward pass 2 & 3, the softmax
381	                // note that softmax (like e.g. tanh) doesn't need the input (preatt) to backward
382	                for (int t2 = 0; t2 <= t; t2++) {
383	                    for (int t3 = 0; t3 <= t; t3++) {
384	                        float indicator = t2 == t3 ? 1.0f : 0.0f;
385	                        float local_derivative = att_bth[t2] * (indicator - att_bth[t3]);
386	                        dpreatt_bth[t3] += local_derivative * datt_bth[t2];
387	                    }
388	                }
389	
390	                // backward pass 1, the query @ key matmul
391	                for (int t2 = 0; t2 <= t; t2++) {
392	                    float* key_t2 = inp + b * T * C3 + t2 * C3 + h * hs + C; // +C because it's key
393	                    float* dkey_t2 = dinp + b * T * C3 + t2 * C3 + h * hs + C; // +C because it's key
394	                    for (int i = 0; i < hs; i++) {
395	                        // in the forward pass this was:
396	                        // preatt_bth[t2] += (query_t[i] * key_t2[i]) * scale;
397	                        // so now we have:
398	                        dquery_t[i] += key_t2[i] * dpreatt_bth[t2] * scale;
399	                        dkey_t2[i] += query_t[i] * dpreatt_bth[t2] * scale;
400	                    }
401	                }
402	            }
403	        }
404	    }
405	}
406	
407	#define GELU_SCALING_FACTOR sqrtf(2.0f / M_PI)
408	void gelu_forward(float* out, float* inp, int N) {
409	    // (approximate) GeLU elementwise non-linearity in the MLP block of Transformer
410	    for (int i = 0; i < N; i++) {
411	        float x = inp[i];
412	        float cube = 0.044715f * x * x * x;
413	        out[i] = 0.5f * x * (1.0f + tanhf(GELU_SCALING_FACTOR * (x + cube)));
414	    }
415	}
416	
417	// we want to use -Ofast optimization, but sadly GeLU breaks, so disable this flag just for it (#168)
418	#pragma float_control(precise, on, push)
419	#if defined(__GNUC__) && !defined(__clang__)
420	__attribute__((optimize("no-finite-math-only")))
421	#endif
422	void gelu_backward(float* dinp, float* inp, float* dout, int N) {
423	    for (int i = 0; i < N; i++) {
424	        float x = inp[i];
425	        float cube = 0.044715f * x * x * x;
426	        float tanh_arg = GELU_SCALING_FACTOR * (x + cube);
427	        float tanh_out = tanhf(tanh_arg);
428	        float coshf_out = coshf(tanh_arg);
429	        float sech_out = 1.0f / (coshf_out * coshf_out);
430	        float local_grad = 0.5f * (1.0f + tanh_out) + x * 0.5f * sech_out * GELU_SCALING_FACTOR * (1.0f + 3.0f * 0.044715f * x * x);
431	        dinp[i] += local_grad * dout[i];
432	    }
433	}
434	#pragma float_control(pop)
435	
436	void residual_forward(float* out, float* inp1, float* inp2, int N) {
437	    for (int i = 0; i < N; i++) {
438	        out[i] = inp1[i] + inp2[i];
439	    }
440	}
441	
442	void residual_backward(float* dinp1, float* dinp2, float* dout, int N) {
443	    for (int i = 0; i < N; i++) {
444	        dinp1[i] += dout[i];
445	        dinp2[i] += dout[i];
446	    }
447	}
448	
449	void softmax_forward(float* probs, float* logits, int B, int T, int V, int Vp) {
450	    // output: probs are (B,T,Vp) of the probabilities (sums to 1.0 in each b,t position)
451	    // input: logits is (B,T,Vp) of the unnormalized log probabilities
452	    // Vp is the padded vocab size (for efficiency), V is the "real" vocab size
453	    // example: Vp is 50304 and V is 50257
454	    #pragma omp parallel for collapse(2)
455	    for (int b = 0; b < B; b++) {
456	        for (int t = 0; t < T; t++) {
457	            // probs <- softmax(logits)
458	            float* logits_bt = logits + b * T * Vp + t * Vp;
459	            float* probs_bt = probs + b * T * Vp + t * Vp;
460	
461	            // maxval is only calculated and subtracted for numerical stability
462	            float maxval = -10000.0f; // TODO something better
463	            for (int i = 0; i < V; i++) {
464	                if (logits_bt[i] > maxval) {
465	                    maxval = logits_bt[i];
466	                }
467	            }
468	            float sum = 0.0f;
469	            for (int i = 0; i < V; i++) {
470	                probs_bt[i] = expf(logits_bt[i] - maxval);
471	                sum += probs_bt[i];
472	            }
473	            // note we only loop to V, leaving the padded dimensions
474	            for (int i = 0; i < V; i++) {
475	                probs_bt[i] /= sum;
476	            }
477	            // for extra super safety we may wish to include this too,
478	            // forcing the probabilities here to be zero, but it shouldn't matter
479	            for (int i = V; i < Vp; i++) {
480	                probs_bt[i] = 0.0f;
481	            }
482	        }
483	    }
484	}
485	
486	void crossentropy_forward(float* losses,
487	                          float* probs, int* targets,
488	                          int B, int T, int Vp) {
489	    // output: losses is (B,T) of the individual losses at each position
490	    // input: probs are (B,T,Vp) of the probabilities
491	    // input: targets is (B,T) of integers giving the correct index in logits
492	    for (int b = 0; b < B; b++) {
493	        for (int t = 0; t < T; t++) {
494	            // loss = -log(probs[target])
495	            float* probs_bt = probs + b * T * Vp + t * Vp;
496	            int ix = targets[b * T + t];
497	            losses[b * T + t] = -logf(probs_bt[ix]);
498	        }
499	    }
500	}
501	
502	void crossentropy_softmax_backward(float* dlogits,
503	                           float* dlosses, float* probs, int* targets,
504	                           int B, int T, int V, int Vp) {
505	    // backwards through both softmax and crossentropy
506	    for (int b = 0; b < B; b++) {
507	        for (int t = 0; t < T; t++) {
508	            float* dlogits_bt = dlogits + b * T * Vp + t * Vp;
509	            float* probs_bt = probs + b * T * Vp + t * Vp;
510	            float dloss = dlosses[b * T + t];
511	            int ix = targets[b * T + t];
512	            // note we only loop to V, leaving the padded dimensions
513	            // of dlogits untouched, so gradient there stays at zero
514	            for (int i = 0; i < V; i++) {
515	                float p = probs_bt[i];
516	                float indicator = i == ix ? 1.0f : 0.0f;
517	                dlogits_bt[i] += (p - indicator) * dloss;
518	            }
519	        }
520	    }
521	}
