525	
526	typedef struct {
527	    int max_seq_len; // max sequence length, e.g. 1024
528	    int vocab_size; // vocab size, e.g. 50257
529	    int padded_vocab_size; // padded to e.g. %128==0, 50304
530	    int num_layers; // number of layers, e.g. 12
531	    int num_heads; // number of heads in attention, e.g. 12
532	    int channels; // number of channels, e.g. 768
533	} GPT2Config;
