535	// the parameters of the model
536	#define NUM_PARAMETER_TENSORS 16
537	typedef struct {
538	    float* wte; // (V, C)
539	    float* wpe; // (maxT, C)
540	    float* ln1w; // (L, C)
541	    float* ln1b; // (L, C)
542	    float* qkvw; // (L, 3*C, C)
543	    float* qkvb; // (L, 3*C)
544	    float* attprojw; // (L, C, C)
545	    float* attprojb; // (L, C)
546	    float* ln2w; // (L, C)
547	    float* ln2b; // (L, C)
548	    float* fcw; // (L, 4*C, C)
549	    float* fcb; // (L, 4*C)
550	    float* fcprojw; // (L, C, 4*C)
551	    float* fcprojb; // (L, C)
552	    float* lnfw; // (C)
553	    float* lnfb; // (C)
554	} ParameterTensors;
