556	void fill_in_parameter_sizes(size_t* param_sizes, GPT2Config config) {
557	    size_t Vp = config.padded_vocab_size;
558	    size_t C = config.channels;
559	    size_t maxT = config.max_seq_len;
560	    size_t L = config.num_layers;
561	    param_sizes[0] = Vp * C; // wte
562	    param_sizes[1] = maxT * C; // wpe
563	    param_sizes[2] = L * C; // ln1w
564	    param_sizes[3] = L * C; // ln1b
565	    param_sizes[4] = L * (3 * C) * C; // qkvw
566	    param_sizes[5] = L * (3 * C); // qkvb
567	    param_sizes[6] = L * C * C; // attprojw
568	    param_sizes[7] = L * C; // attprojb
569	    param_sizes[8] = L * C; // ln2w
570	    param_sizes[9] = L * C; // ln2b
571	    param_sizes[10] = L * (4 * C) * C; // fcw
572	    param_sizes[11] = L * (4 * C); // fcb
573	    param_sizes[12] = L * C * (4 * C); // fcprojw
574	    param_sizes[13] = L * C; // fcprojb
575	    param_sizes[14] = C; // lnfw
576	    param_sizes[15] = C; // lnfb
577	}
578	
579	// allocate memory for the parameters and point the individual tensors to the right places
580	float* malloc_and_point_parameters(ParameterTensors* params, size_t* param_sizes) {
581	    size_t num_parameters = 0;
582	    for (size_t i = 0; i < NUM_PARAMETER_TENSORS; i++) {
583	        num_parameters += param_sizes[i];
584	    }
585	    // malloc all parameters all at once
586	    float* params_memory = (float*)mallocCheck(num_parameters * sizeof(float));
587	    // assign all the tensors
588	    float** ptrs[] = {
589	        &params->wte, &params->wpe, &params->ln1w, &params->ln1b, &params->qkvw, &params->qkvb,
590	        &params->attprojw, &params->attprojb, &params->ln2w, &params->ln2b, &params->fcw, &params->fcb,
591	        &params->fcprojw, &params->fcprojb, &params->lnfw, &params->lnfb
592	    };
593	    float* params_memory_iterator = params_memory;
594	    for (size_t i = 0; i < NUM_PARAMETER_TENSORS; i++) {
595	        *(ptrs[i]) = params_memory_iterator;
596	        params_memory_iterator += param_sizes[i];
597	    }
598	    return params_memory;
599	}
