628	void fill_in_activation_sizes(size_t* act_sizes, GPT2Config config, int B, int T) {
629	    size_t C = config.channels;
630	    size_t NH = config.num_heads;
631	    size_t L = config.num_layers;
632	    size_t Vp = config.padded_vocab_size;
633	    act_sizes[0] = B * T * C; // encoded
634	    act_sizes[1] = L * B * T * C; // ln1
635	    act_sizes[2] = L * B * T; // ln1_mean
636	    act_sizes[3] = L * B * T; // ln1_rstd
637	    act_sizes[4] = L * B * T * 3 * C; // qkv
638	    act_sizes[5] = L * B * T * C; // atty
639	    act_sizes[6] = L * B * NH * T * T; // preatt
640	    act_sizes[7] = L * B * NH * T * T; // att
641	    act_sizes[8] = L * B * T * C; // attproj
642	    act_sizes[9] = L * B * T * C; // residual2
643	    act_sizes[10] = L * B * T * C; // ln2
644	    act_sizes[11] = L * B * T; // ln2_mean
645	    act_sizes[12] = L * B * T; // ln2_rstd
646	    act_sizes[13] = L * B * T * 4 * C; // fch
647	    act_sizes[14] = L * B * T * 4 * C; // fch_gelu
648	    act_sizes[15] = L * B * T * C; // fcproj
649	    act_sizes[16] = L * B * T * C; // residual3
650	    act_sizes[17] = B * T * C; // lnf
651	    act_sizes[18] = B * T; // lnf_mean
652	    act_sizes[19] = B * T; // lnf_rstd
653	    act_sizes[20] = B * T * Vp; // logits
654	    act_sizes[21] = B * T * Vp; // probs
655	    act_sizes[22] = B * T; // losses
656	}
