658	float* malloc_and_point_activations(ActivationTensors* acts, size_t* act_sizes) {
659	    size_t num_activations = 0;
660	    for (size_t i = 0; i < NUM_ACTIVATION_TENSORS; i++) {
661	        num_activations += act_sizes[i];
662	    }
663	    float* acts_memory = (float*)mallocCheck(num_activations * sizeof(float));
664	    float** ptrs[] = {
665	        &acts->encoded, &acts->ln1, &acts->ln1_mean, &acts->ln1_rstd, &acts->qkv, &acts->atty,
666	        &acts->preatt, &acts->att, &acts->attproj, &acts->residual2, &acts->ln2, &acts->ln2_mean,
667	        &acts->ln2_rstd, &acts->fch, &acts->fch_gelu, &acts->fcproj, &acts->residual3, &acts->lnf,
668	        &acts->lnf_mean, &acts->lnf_rstd, &acts->logits, &acts->probs, &acts->losses
669	    };
670	    float* acts_memory_iterator = acts_memory;
671	    for (size_t i = 0; i < NUM_ACTIVATION_TENSORS; i++) {
672	        *(ptrs[i]) = acts_memory_iterator;
