707	void gpt2_build_from_checkpoint(GPT2 *model, const char* checkpoint_path) {
708	
709	    // read in model from a checkpoint file
710	    FILE *model_file = fopenCheck(checkpoint_path, "rb");
711	    int model_header[256];
712	    freadCheck(model_header, sizeof(int), 256, model_file);
713	    if (model_header[0] != 20240326) { printf("Bad magic model file\n"); exit(1); }
714	    if (model_header[1] != 3) {
715	        printf("Bad version in model file\n");
716	        printf("---> HINT: try to re-run `python train_gpt2.py`\n");
717	        exit(1);
718	    }
719	
720	    // read in hyperparameters
721	    size_t maxT, V, Vp, L, NH, C; // size_t to prevent int overflow
722	    model->config.max_seq_len = maxT = model_header[2];
723	    model->config.vocab_size = V = model_header[3];
724	    model->config.num_layers = L = model_header[4];
725	    model->config.num_heads = NH = model_header[5];
726	    model->config.channels = C = model_header[6];
727	    model->config.padded_vocab_size = Vp = model_header[7];
728	    printf("[GPT-2]\n");
729	    printf("max_seq_len: %zu\n", maxT);
730	    printf("vocab_size: %zu\n", V);
731	    printf("padded_vocab_size: %zu\n", Vp);
732	    printf("num_layers: %zu\n", L);
733	    printf("num_heads: %zu\n", NH);
734	    printf("channels: %zu\n", C);
735	
736	    // allocate space for all the parameters and read them in
737	    fill_in_parameter_sizes(model->param_sizes,  model->config);
738	
739	    // count the number of parameters
740	    size_t num_parameters = 0;
741	    for (size_t i = 0; i < NUM_PARAMETER_TENSORS; i++) {
742	        num_parameters += model->param_sizes[i];
743	    }
744	    printf("num_parameters: %zu\n", num_parameters);
745	    model->num_parameters = num_parameters;
746	
747	    // read in all the parameters from file
748	    model->params_memory = malloc_and_point_parameters(&model->params, model->param_sizes);
749	    freadCheck(model->params_memory, sizeof(float), num_parameters, model_file);
750	    fcloseCheck(model_file);
751	
752	    // other inits
753	    model->acts_memory = NULL;
754	    model->grads_memory = NULL;
755	    model->m_memory = NULL;
756	    model->v_memory = NULL;
757	    model->grads_acts_memory = NULL;
758	    model->inputs = NULL;
759	    model->targets = NULL;
760	    model->batch_size = 0;
761	    model->seq_len = 0;
762	    model->mean_loss = -1.0f; // -1.0f will designate no loss
763	}
764	
765	void gpt2_forward(GPT2 *model, int* inputs, int* targets, size_t B, size_t T) {
766	    // targets are optional and could be NULL
767	
768	    // ensure the model was initialized or error out
769	    if (model->params_memory == NULL) {
770	        printf("Error: model was not initialized properly.\n");
771	        exit(1);
772	    }
773	
774	    // convenience parameters (size_t to help prevent int overflow)
775	    size_t V = model->config.vocab_size;
776	    size_t Vp = model->config.padded_vocab_size;
777	    size_t L = model->config.num_layers;
778	    size_t NH = model->config.num_heads;
779	    size_t C = model->config.channels;
780	
781	    // validate inputs, all indices must be in the range [0, V)
782	    for(int i = 0; i < B * T; i++) {
783	        assert(0 <= inputs[i] && inputs[i] < V);
784	        if (targets != NULL) {
785	            assert(0 <= targets[i] && targets[i] < V);
786	        }
787	    }
788	
789	    // allocate space for all the activations if needed (done here, lazily)
790	    if(model->acts_memory == NULL) {
791	        // record the current B,T as well
792	        model->batch_size = B;
793	        model->seq_len = T;
794	        // and now allocate the space
795	        fill_in_activation_sizes(model->act_sizes, model->config, B, T);
796	        size_t num_activations = 0;
797	        for (size_t i = 0; i < NUM_ACTIVATION_TENSORS; i++) {
798	            num_activations += model->act_sizes[i];
799	        }
800	        printf("num_activations: %zu\n", num_activations);
801	        model->num_activations = num_activations;
802	        model->acts_memory = malloc_and_point_activations(&model->acts, model->act_sizes);
803	        // also create memory for caching inputs and targets
804	        model->inputs = (int*)mallocCheck(B * T * sizeof(int));
805	        model->targets = (int*)mallocCheck(B * T * sizeof(int)); // might be unused if we never have targets but it's small
806	    } else {
807	        // validate B,T is consistent with how we've allocated the memory before
808	        // in principle we could get more clever here in the future, for now this is safest
809	        if (B != model->batch_size || T != model->seq_len) {
810	            printf("Model: B=%d T=%d, Desired: B=%d T=%d\n", model->batch_size, model->seq_len, (int)B, (int)T);
811	            exit(EXIT_FAILURE);
812	        }
813	    }
814	
815	    // cache the inputs/targets
816	    memcpy(model->inputs, inputs, B * T * sizeof(int));
817	    if (targets != NULL) {
818	        memcpy(model->targets, targets, B * T * sizeof(int));
819	    }
820	
821	    // forward pass
822	    ParameterTensors params = model->params; // for brevity
823	    ActivationTensors acts = model->acts;
824	    float* residual;
825	    encoder_forward(acts.encoded, inputs, params.wte, params.wpe, B, T, C); // encoding goes into residual[0]
826	    for (int l = 0; l < L; l++) {
827	
828	        residual = l == 0 ? acts.encoded : acts.residual3 + (l-1) * B * T * C;
829	
830	        // get the pointers of the weights for this layer
831	        float* l_ln1w = params.ln1w + l * C;
832	        float* l_ln1b = params.ln1b + l * C;
833	        float* l_qkvw = params.qkvw + l * 3*C * C;
834	        float* l_qkvb = params.qkvb + l * 3*C;
835	        float* l_attprojw = params.attprojw + l * C * C;
836	        float* l_attprojb = params.attprojb + l * C;
837	        float* l_ln2w = params.ln2w + l * C;
838	        float* l_ln2b = params.ln2b + l * C;
839	        float* l_fcw = params.fcw + l * 4*C * C;
840	        float* l_fcb = params.fcb + l * 4*C;
841	        float* l_fcprojw = params.fcprojw + l * C * 4*C;
842	        float* l_fcprojb = params.fcprojb + l * C;
843	
844	        // get the pointers of the activations for this layer
845	        float* l_ln1 = acts.ln1 + l * B * T * C;
846	        float* l_ln1_mean = acts.ln1_mean + l * B * T;
847	        float* l_ln1_rstd = acts.ln1_rstd + l * B * T;
848	        float* l_qkv = acts.qkv + l * B * T * 3*C;
849	        float* l_atty = acts.atty + l * B * T * C;
850	        float* l_preatt = acts.preatt + l * B * NH * T * T;
851	        float* l_att = acts.att + l * B * NH * T * T;
852	        float* l_attproj = acts.attproj + l * B * T * C;
853	        float* l_residual2 = acts.residual2 + l * B * T * C;
854	        float* l_ln2 = acts.ln2 + l * B * T * C;
855	        float* l_ln2_mean = acts.ln2_mean + l * B * T;
856	        float* l_ln2_rstd = acts.ln2_rstd + l * B * T;
857	        float* l_fch = acts.fch + l * B * T * 4*C;
858	        float* l_fch_gelu = acts.fch_gelu + l * B * T * 4*C;
859	        float* l_fcproj = acts.fcproj + l * B * T * C;
860	        float* l_residual3 = acts.residual3 + l * B * T * C;
861	
862	        // now do the forward pass
863	        layernorm_forward(l_ln1, l_ln1_mean, l_ln1_rstd, residual, l_ln1w, l_ln1b, B, T, C);
864	        matmul_forward(l_qkv, l_ln1, l_qkvw, l_qkvb, B, T, C, 3*C);
865	        attention_forward(l_atty, l_preatt, l_att, l_qkv, B, T, C, NH);
866	        matmul_forward(l_attproj, l_atty, l_attprojw, l_attprojb, B, T, C, C);
867	        residual_forward(l_residual2, residual, l_attproj, B*T*C);
868	        layernorm_forward(l_ln2, l_ln2_mean, l_ln2_rstd, l_residual2, l_ln2w, l_ln2b, B, T, C);
869	        matmul_forward(l_fch, l_ln2, l_fcw, l_fcb, B, T, C, 4*C);
870	        gelu_forward(l_fch_gelu, l_fch, B*T*4*C);
871	        matmul_forward(l_fcproj, l_fch_gelu, l_fcprojw, l_fcprojb, B, T, 4*C, C);
872	        residual_forward(l_residual3, l_residual2, l_fcproj, B*T*C);
873	    }
874	    residual = acts.residual3 + (L-1) * B * T * C; // last residual is in residual3
875	    layernorm_forward(acts.lnf, acts.lnf_mean, acts.lnf_rstd, residual, params.lnfw, params.lnfb, B, T, C);
876	    matmul_forward(acts.logits, acts.lnf, params.wte, NULL, B, T, C, Vp);
877	    softmax_forward(acts.probs, acts.logits, B, T, V, Vp);
878	
879	    // also forward the cross-entropy loss function if we have the targets
880	    if (targets != NULL) {
881	        crossentropy_forward(model->acts.losses, model->acts.probs, targets, B, T, Vp);
882	        // for convenience also evaluate the mean loss
883	        float mean_loss = 0.0f;
884	        for (int i=0; i<B*T; i++) { mean_loss += model->acts.losses[i]; }
885	        mean_loss /= B*T;
886	        model->mean_loss = mean_loss;
887	    } else {
888	        // if we don't have targets, we don't have a loss
889	        model->mean_loss = -1.0f;
890	    }
891	}
892	
893	void gpt2_zero_grad(GPT2 *model) {
894	    if(model->grads_memory != NULL) { memset(model->grads_memory, 0, model->num_parameters * sizeof(float)); }
895	    if(model->grads_acts_memory != NULL) { memset(model->grads_acts_memory, 0, model->num_activations * sizeof(float)); }
896	}
897	
898	void gpt2_backward(GPT2 *model) {
899	
900	    // double check we forwarded previously, with targets
901	    if (model->mean_loss == -1.0f) {
902	        printf("Error: must forward with targets before backward\n");
903	        exit(1);
904	    }
905	
906	    // lazily allocate the memory for gradients of the weights and activations, if needed
907	    if (model->grads_memory == NULL) {
908	        model->grads_memory = malloc_and_point_parameters(&model->grads, model->param_sizes);
909	        model->grads_acts_memory = malloc_and_point_activations(&model->grads_acts, model->act_sizes);
910	        gpt2_zero_grad(model);
911	    }
912	
913	    // convenience shortcuts (and size_t to help prevent int overflow)
914	    size_t B = model->batch_size;
915	    size_t T = model->seq_len;
916	    size_t V = model->config.vocab_size;
917	    size_t Vp = model->config.padded_vocab_size;
918	    size_t L = model->config.num_layers;
919	    size_t NH = model->config.num_heads;
920	    size_t C = model->config.channels;
921	
922	    // backward pass: go in the reverse order of the forward pass, and call backward() functions
923	    ParameterTensors params = model->params; // for brevity
924	    ParameterTensors grads = model->grads;
925	    ActivationTensors acts = model->acts;
926	    ActivationTensors grads_acts = model->grads_acts;
927	
928	    // we kick off the chain rule by filling in dlosses with 1.0f/(B*T)
929	    // technically this is a small, inline backward() pass of calculating
930	    // total, final loss as the mean over all losses over all (B,T) positions in the batch
931	    float dloss_mean = 1.0f / (B*T);
932	    for (int i = 0; i < B*T; i++) { grads_acts.losses[i] = dloss_mean; }
933	
934	    crossentropy_softmax_backward(grads_acts.logits, grads_acts.losses, acts.probs, model->targets, B, T, V, Vp);
935	    matmul_backward(grads_acts.lnf, grads.wte, NULL, grads_acts.logits, acts.lnf, params.wte, B, T, C, Vp);
936	    float* residual = acts.residual3 + (L-1) * B * T * C; // last layer's residual
937	    float* dresidual = grads_acts.residual3 + (L-1) * B * T * C; // write to last layer's residual
938	    layernorm_backward(dresidual, grads.lnfw, grads.lnfb, grads_acts.lnf, residual, params.lnfw, acts.lnf_mean, acts.lnf_rstd, B, T, C);
939	
940	    for (int l = L-1; l >= 0; l--) {
941	
942	        residual = l == 0 ? acts.encoded : acts.residual3 + (l-1) * B * T * C;
943	        dresidual = l == 0 ? grads_acts.encoded : grads_acts.residual3 + (l-1) * B * T * C;
944	
945	        // get the pointers of the weights for this layer
946	        float* l_ln1w = params.ln1w + l * C;
947	        float* l_qkvw = params.qkvw + l * 3*C * C;
948	        float* l_attprojw = params.attprojw + l * C * C;
949	        float* l_ln2w = params.ln2w + l * C;
950	        float* l_fcw = params.fcw + l * 4*C * C;
951	        float* l_fcprojw = params.fcprojw + l * C * 4*C;
952	        // get the pointers of the gradients of the weights for this layer
953	        float* dl_ln1w = grads.ln1w + l * C;
954	        float* dl_ln1b = grads.ln1b + l * C;
955	        float* dl_qkvw = grads.qkvw + l * 3*C * C;
956	        float* dl_qkvb = grads.qkvb + l * 3*C;
957	        float* dl_attprojw = grads.attprojw + l * C * C;
958	        float* dl_attprojb = grads.attprojb + l * C;
959	        float* dl_ln2w = grads.ln2w + l * C;
960	        float* dl_ln2b = grads.ln2b + l * C;
961	        float* dl_fcw = grads.fcw + l * 4*C * C;
962	        float* dl_fcb = grads.fcb + l * 4*C;
963	        float* dl_fcprojw = grads.fcprojw + l * C * 4*C;
964	        float* dl_fcprojb = grads.fcprojb + l * C;
965	        // get the pointers of the activations for this layer
966	        float* l_ln1 = acts.ln1 + l * B * T * C;
967	        float* l_ln1_mean = acts.ln1_mean + l * B * T;
968	        float* l_ln1_rstd = acts.ln1_rstd + l * B * T;
969	        float* l_qkv = acts.qkv + l * B * T * 3*C;
970	        float* l_atty = acts.atty + l * B * T * C;
971	        float* l_att = acts.att + l * B * NH * T * T;
972	        float* l_residual2 = acts.residual2 + l * B * T * C;
973	        float* l_ln2 = acts.ln2 + l * B * T * C;
974	        float* l_ln2_mean = acts.ln2_mean + l * B * T;
975	        float* l_ln2_rstd = acts.ln2_rstd + l * B * T;
976	        float* l_fch = acts.fch + l * B * T * 4*C;
977	        float* l_fch_gelu = acts.fch_gelu + l * B * T * 4*C;
978	        // get the pointers of the gradients of the activations for this layer
979	        float* dl_ln1 = grads_acts.ln1 + l * B * T * C;
980	        float* dl_qkv = grads_acts.qkv + l * B * T * 3*C;
981	        float* dl_atty = grads_acts.atty + l * B * T * C;
982	        float* dl_preatt = grads_acts.preatt + l * B * NH * T * T;
983	        float* dl_att = grads_acts.att + l * B * NH * T * T;
984	        float* dl_attproj = grads_acts.attproj + l * B * T * C;
985	        float* dl_residual2 = grads_acts.residual2 + l * B * T * C;
986	        float* dl_ln2 = grads_acts.ln2 + l * B * T * C;
987	        float* dl_fch = grads_acts.fch + l * B * T * 4*C;
988	        float* dl_fch_gelu = grads_acts.fch_gelu + l * B * T * 4*C;
989	        float* dl_fcproj = grads_acts.fcproj + l * B * T * C;
990	        float* dl_residual3 = grads_acts.residual3 + l * B * T * C;
991	
992	        // backprop this layer
993	        residual_backward(dl_residual2, dl_fcproj, dl_residual3, B*T*C);
994	        matmul_backward(dl_fch_gelu, dl_fcprojw, dl_fcprojb, dl_fcproj, l_fch_gelu, l_fcprojw, B, T, 4*C, C);
995	        gelu_backward(dl_fch, l_fch, dl_fch_gelu, B*T*4*C);
996	        matmul_backward(dl_ln2, dl_fcw, dl_fcb, dl_fch, l_ln2, l_fcw, B, T, C, 4*C);
997	        layernorm_backward(dl_residual2, dl_ln2w, dl_ln2b, dl_ln2, l_residual2, l_ln2w, l_ln2_mean, l_ln2_rstd, B, T, C);
998	        residual_backward(dresidual, dl_attproj, dl_residual2, B*T*C);
999	        matmul_backward(dl_atty, dl_attprojw, dl_attprojb, dl_attproj, l_atty, l_attprojw, B, T, C, C);
1000	        attention_backward(dl_qkv, dl_preatt, dl_att, dl_atty, l_qkv, l_att, B, T, C, NH);
1001	        matmul_backward(dl_ln1, dl_qkvw, dl_qkvb, dl_qkv, l_ln1, l_qkvw, B, T, C, 3*C);
1002	        layernorm_backward(dresidual, dl_ln1w, dl_ln1b, dl_ln1, residual, l_ln1w, l_ln1_mean, l_ln1_rstd, B, T, C);
1003	    }
1004	    encoder_backward(grads.wte, grads.wpe, grads_acts.encoded, model->inputs, B, T, C);
1005	}
1006	
1007	void gpt2_update(GPT2 *model, float learning_rate, float beta1, float beta2, float eps, float weight_decay, int t) {
1008	    // reference: https://pytorch.org/docs/stable/generated/torch.optim.AdamW.html
1009	
1010	    // lazily allocate the memory for m_memory and v_memory
1011	    if (model->m_memory == NULL) {
1012	        model->m_memory = (float*)calloc(model->num_parameters, sizeof(float));
1013	        model->v_memory = (float*)calloc(model->num_parameters, sizeof(float));
1014	    }
1015	
1016	    for (size_t i = 0; i < model->num_parameters; i++) {
1017	        float param = model->params_memory[i];
1018	        float grad = model->grads_memory[i];
1019	
1020	        // update the first moment (momentum)
1021	        float m = beta1 * model->m_memory[i] + (1.0f - beta1) * grad;
1022	        // update the second moment (RMSprop)
1023	        float v = beta2 * model->v_memory[i] + (1.0f - beta2) * grad * grad;
1024	        // bias-correct both moments
1025	        float m_hat = m / (1.0f - powf(beta1, t));
1026	        float v_hat = v / (1.0f - powf(beta2, t));
1027	
1028	        // update
1029	        model->m_memory[i] = m;
1030	        model->v_memory[i] = v;
1031	        model->params_memory[i] -= learning_rate * (m_hat / (sqrtf(v_hat) + eps) + weight_decay * param);
1032	    }
1033	}
1034	
1035	void gpt2_free(GPT2 *model) {
1036	    free(model->params_memory);
1037	    free(model->grads_memory);
1038	    free(model->m_memory);
1039	    free(model->v_memory);
1040	    free(model->acts_memory);
1041	    free(model->grads_acts_memory);
1042	    free(model->inputs);
1043	    free(model->targets);
1044	}
1045	
1046	#ifndef TESTING
1047	// if we are TESTING (see test_gpt2.c), we'll skip the int main below
1048	// ----------------------------------------------------------------------------
1049	// sampler
1050	
1051	unsigned int random_u32(uint64_t *state) {
1052	    // xorshift rng: https://en.wikipedia.org/wiki/Xorshift#xorshift.2A
1053	    *state ^= *state >> 12;
1054	    *state ^= *state << 25;
1055	    *state ^= *state >> 27;
1056	    return (*state * 0x2545F4914F6CDD1Dull) >> 32;
1057	}
1058	float random_f32(uint64_t *state) { // random float32 in [0,1)
1059	    return (random_u32(state) >> 8) / 16777216.0f;
1060	}
1061	
1062	int sample_mult(float* probabilities, int n, float coin) {
1063	    // sample index from probabilities (they must sum to 1!)
1064	    // coin is a random number in [0, 1), usually from random_f32()
1065	    float cdf = 0.0f;
1066	    for (int i = 0; i < n; i++) {
1067	        cdf += probabilities[i];
1068	        if (coin < cdf) {
1069	            return i;
1070	        }
1071	    }
1072	    return n - 1; // in case of rounding errors
1073	}
1074	
1075	// ----------------------------------------------------------------------------
1076	// main training loop
1077	int main() {
1078	
1079	    // build the GPT-2 model from a checkpoint
1080	    GPT2 model;
1081	    gpt2_build_from_checkpoint(&model, "gpt2_124M.bin");
1082	
1083	    // build the DataLoaders from tokens files. for now use tiny_shakespeare if available, else tiny_stories
1084	    const char* tiny_stories_train = "dev/data/tinystories/TinyStories_train.bin";
1085	    const char* tiny_stories_val = "dev/data/tinystories/TinyStories_val.bin";
1086	    const char* tiny_shakespeare_train = "dev/data/tinyshakespeare/tiny_shakespeare_train.bin";
1087	    const char* tiny_shakespeare_val = "dev/data/tinyshakespeare/tiny_shakespeare_val.bin";
1088	    const char* train_tokens = access(tiny_shakespeare_train, F_OK) != -1 ? tiny_shakespeare_train : tiny_stories_train;
1089	    const char* val_tokens = access(tiny_shakespeare_val, F_OK) != -1 ? tiny_shakespeare_val : tiny_stories_val;
1090	    int B = 4; // batch size 4 (i.e. 4 independent token sequences will be trained on)
1091	    int T = 64; // sequence length 64 (i.e. each sequence is 64 tokens long). must be <= maxT, which is 1024 for GPT-2
1092	    DataLoader train_loader, val_loader;
1093	    dataloader_init(&train_loader, train_tokens, B, T, 0, 1, 1);
1094	    dataloader_init(&val_loader, val_tokens, B, T, 0, 1, 0);
1095	    printf("train dataset num_batches: %zu\n", train_loader.num_tokens / (B*T));
1096	    printf("val dataset num_batches: %zu\n", val_loader.num_tokens / (B*T));
1097	    int val_num_batches = 5;
1098	
1099	    // build the Tokenizer
1100	    Tokenizer tokenizer;
1101	    tokenizer_init(&tokenizer, "gpt2_tokenizer.bin");
1102	
1103	    // some memory for generating samples from the model
1104	    uint64_t rng_state = 1337;
1105	    int* gen_tokens = (int*)mallocCheck(B * T * sizeof(int));
1106	    const int genT = 64; // number of steps of inference we will do
1107	
1108	    // train
1109	    struct timespec start, end;
1110	    for (int step = 0; step <= 40; step++) {
1111	
1112	        // once in a while estimate the validation loss
1113	        if (step % 10 == 0) {
1114	            float val_loss = 0.0f;
1115	            dataloader_reset(&val_loader);
1116	            for (int i = 0; i < val_num_batches; i++) {
1117	                dataloader_next_batch(&val_loader);
1118	                gpt2_forward(&model, val_loader.inputs, val_loader.targets, B, T);
1119	                val_loss += model.mean_loss;
1120	            }
1121	            val_loss /= val_num_batches;
1122	            printf("val loss %f\n", val_loss);
1123	        }
1124	
1125	        // once in a while do model inference to print generated text
1126	        if (step > 0 && step % 20 == 0) {
1127	            // fill up gen_tokens with the GPT2_EOT, which kicks off the generation
1128	            for(int i = 0; i < B * T; ++i) {
1129	                gen_tokens[i] = tokenizer.eot_token;
1130	            }
1131	            // now sample from the model autoregressively
1132	            printf("generating:\n---\n");
1133	            for (int t = 1; t < genT; t++) {
1134	                // note that inference is very wasteful here because for each token
1135	                // we re-calculate the forward pass for all of (B,T) positions from scratch
1136	                // but the inference here is just for sanity checking anyway
1137	                // and we can maybe optimize a bit more later, with careful tests
1138	                gpt2_forward(&model, gen_tokens, NULL, B, T);
1139	                // furthermore, below we're only using b=0 (i.e. the first row) of all B rows
1140	                // we're in principle running B "inference streams" in parallel here
1141	                // but only using position 0
1142	                // get the Vp-dimensional vector probs[0, t-1, :]
1143	                float* probs = model.acts.probs + (t-1) * model.config.padded_vocab_size;
1144	                float coin = random_f32(&rng_state);
1145	                // note we're only sampling from the first V elements, ignoring padding
1146	                // (the probabilities in the padded region should be zero anyway)
1147	                int next_token = sample_mult(probs, model.config.vocab_size, coin);
1148	                gen_tokens[t] = next_token;
1149	                // print the generated token, either using the Tokenizer or a fallback
1150	                if (tokenizer.init_ok) {
1151	                    const char* token_str = tokenizer_decode(&tokenizer, next_token);
1152	                    safe_printf(token_str);
1153	                } else {
1154	                    // fall back to printing the token id
1155	                    printf("%d ", next_token);
1156	                }
1157	                fflush(stdout);
1158	            }
1159	            printf("\n---\n");
1160	        }
1161	
1162	        // do a training step
1163	        clock_gettime(CLOCK_MONOTONIC, &start);
1164	        dataloader_next_batch(&train_loader);
1165	        gpt2_forward(&model, train_loader.inputs, train_loader.targets, B, T);
1166	        gpt2_zero_grad(&model);
1167	        gpt2_backward(&model);
1168	        gpt2_update(&model, 1e-4f, 0.9f, 0.999f, 1e-8f, 0.0f, step+1);
1169	        clock_gettime(CLOCK_MONOTONIC, &end);
1170	        double time_elapsed_s = (end.tv_sec - start.tv_sec) + (end.tv_nsec - start.tv_nsec) / 1e9;
1171	        printf("step %d: train loss %f (took %f ms)\n", step, model.mean_loss, time_elapsed_s * 1000);
1172	    }
1173	
1174	    // free
1175	    dataloader_free(&train_loader);
1176	    dataloader_free(&val_loader);
1177	    tokenizer_free(&tokenizer);
1178	    gpt2_free(&model);
1179	    free(gen_tokens);
1180	    return 0;
1181	}
1182	#endif
